//drive.google.com/thumbnail?id=1d7vYzB7O0PTP63MyGJmCP2PuNUKwDO8N&sz=w1600\",\"alt\":\"\",\"scale\":75}],\"fill\":\"#FFFFFF\",\"imageFlow\":\"horizontal\",\"cardMaxWidth\":\"full\",\"cardStroke\":false,\"fillOpacity\":\"clear\",\"imageAlign\":\"center\"}]","cb_e-learning-course-videos":"[{\"id\":\"8z8hfdv\",\"type\":\"section\",\"sectionTitle\":\"Infographic Reel\"},{\"id\":\"4axu0k0\",\"type\":\"text\",\"content\":\"<div class=\\\"heading-lg\\\">Animation Reel</div><div class=\\\"label\\\">Mar 2025</div><div class=\\\"label\\\"><div class=\\\"body-base\\\" style=\\\"font-family: &quot;PP Neue Bit&quot;, &quot;Courier New&quot;, monospace; font-weight: 400; letter-spacing: normal; text-transform: none;\\\">From 2020 to present I've been animating E-Learning videos for the online school Product Institute. The reel below highlights some of my favorite scenes to date. Im an entirely self taught animator (YouTube University) and I'm constantly looking to improve my skills.&nbsp;</div></div>\",\"fill\":\"#FFFFFF\"},{\"id\":\"4ri6fl2\",\"type\":\"video\",\"url\":\"<iframe width=\\\"560\\\" height=\\\"315\\\" src=\\\"https://www.youtube.com/embed/9DNoTvXdasI?si=yAyhv3m7fFqH_0jg\\\" title=\\\"YouTube video player\\\" frameborder=\\\"0\\\" allow=\\\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\\\" referrerpolicy=\\\"strict-origin-when-cross-origin\\\" allowfullscreen></iframe>\",\"fill\":\"#FFFFFF\",\"hugTop\":true},{\"id\":\"x2aeun9\",\"type\":\"section\",\"sectionTitle\":\"Animated UX UI Reel\"},{\"id\":\"xm5ur3q\",\"type\":\"text\",\"content\":\"<div class=\\\"heading-md\\\">Animated UX UI Reel</div><div class=\\\"label\\\">Mar 2025</div><div class=\\\"body-base\\\">User Interfaces are a common visual used in Product Institute videos. The goal of these scenes is always to enhance the lesson content, only highlighting the user interaction being discussed in as low fidelity as possible. This reel highlights some of the animated user interfaces and other scenes that use <b>heavy typography.</b></div>\",\"fill\":\"#FFFFFF\"},{\"id\":\"2ud04lq\",\"type\":\"video\",\"url\":\"<iframe width=\\\"560\\\" height=\\\"315\\\" src=\\\"https://www.youtube.com/embed/5kT6L2R7eW8?si=XQcy9ISIBKfFFrz-\\\" title=\\\"YouTube video player\\\" frameborder=\\\"0\\\" allow=\\\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\\\" referrerpolicy=\\\"strict-origin-when-cross-origin\\\" allowfullscreen></iframe>\",\"fill\":\"#404040\",\"hugTop\":true},{\"id\":\"9rsr69e\",\"type\":\"spacer\",\"spacerHeight\":8},{\"id\":\"7grlylm\",\"type\":\"section\",\"sectionTitle\":\"After Effects Templates\"},{\"id\":\"3i0cwno\",\"type\":\"group\",\"fill\":\"#FFFFFF\",\"children\":[{\"id\":\"x3jguj3\",\"type\":\"text\",\"content\":\"<div class=\\\"heading-md\\\">Templates</div><div class=\\\"body-base\\\">Over the 6+ years I've worked at Product Institute, I animated over 4 hours of course content. It was very important for me to be intentional and resourceful with my after effects compositions. Here are a collection of templates from my animation style guide folder.</div>\"},{\"id\":\"idqf547\",\"type\":\"text\",\"content\":\"<div class=\\\"heading-sm\\\">Comparison Side by Side</div>\"},{\"id\":\"n27egqm\",\"type\":\"image\",\"images\":[{\"src\":\"https://drive.google.com/thumbnail?id=1YniR6nYENV_7jMwzTpXS4Rt2tvgPADCI&sz=w1600\",\"alt\":\"\",\"scale\":100},{\"src\":\"https://drive.google.com/thumbnail?id=1dWlpPdVlrXIja4wrwPWT7-qrIrEJXmRt&sz=w1600\",\"alt\":\"\",\"scale\":100},{\"src\":\"https://drive.google.com/thumbnail?id=12Zq6g1ODT7ERGwSD5py-XXLvZ8Trbydk&sz=w1600\",\"alt\":\"\",\"scale\":100},{\"src\":\"https://drive.google.com/thumbnail?id=1wJ-KOk65UMzZ7AD2NmYU2NCxs7DDa3Bd&sz=w1600\",\"alt\":\"\",\"scale\":100}],\"imageGridMode\":true},{\"id\":\"a6d5sxi\",\"type\":\"text\",\"content\":\"<div class=\\\"heading-sm\\\">Office Presentation</div>\"},{\"id\":\"ualk0p8\",\